using System;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.WebSockets;
using System.Threading;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;
using PitWall.Models;

namespace PitWall.WebSocket
{
    /// <summary>
    /// Real-time WebSocket server for broadcasting telemetry to connected clients.
    /// Manages multiple concurrent client connections with high-frequency async telemetry broadcast.
    /// </summary>
    public class WebSocketServer : IWebSocketServer, IDisposable
    {
        private readonly HttpListener _httpListener;
        private readonly ILogger<WebSocketServer> _logger;
        private readonly ConcurrentDictionary<string, WebSocketConnectionHandler> _connectedClients;
        private readonly CancellationTokenSource _serverCancellation;
        private bool _isRunning;
        private bool _disposed;
        private long _totalConnections;
        private long _totalMessages;
        private DateTime _serverStartTime;

        public int Port { get; }
        public bool IsRunning => _isRunning;
        public int ConnectedClientsCount => _connectedClients.Count;

        public WebSocketServer(ILogger<WebSocketServer> logger, int port = 9999)
        {
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
            Port = port;
            _httpListener = new HttpListener();
            _connectedClients = new ConcurrentDictionary<string, WebSocketConnectionHandler>();
            _serverCancellation = new CancellationTokenSource();
            _isRunning = false;
            _disposed = false;
            _totalConnections = 0;
            _totalMessages = 0;

            _logger.LogInformation(\n                \"WebSocket server initialized. Port: {Port}\",\n                Port);\n        }\n\n        /// <summary>\n        /// Starts the WebSocket server with async accept loop.\n        /// </summary>\n        public async Task StartAsync(CancellationToken externalCancellation = default)\n        {\n            ThrowIfDisposed();\n\n            if (_isRunning)\n            {\n                _logger.LogWarning(\"WebSocket server already running\");\n                return;\n            }\n\n            try\n            {\n                var prefix = $\"http://localhost:{Port}/\";\n                _httpListener.Prefixes.Add(prefix);\n                _httpListener.Start();\n                _isRunning = true;\n                _serverStartTime = DateTime.UtcNow;\n\n                _logger.LogInformation(\n                    \"WebSocket server started. Listening on {Prefix}\",\n                    prefix);\n\n                // Create linked token for external cancellation\n                using var linkedTokenSource = CancellationTokenSource.CreateLinkedTokenSource(\n                    externalCancellation, _serverCancellation.Token);\n\n                // Start accept loop in background\n#pragma warning disable CS4014 // Fire and forget for background listener\n                _ = AcceptClientConnectionsAsync(linkedTokenSource.Token);\n#pragma warning restore CS4014\n            }\n            catch (Exception ex)\n            {\n                _isRunning = false;\n                _logger.LogError(\n                    ex,\n                    \"Error starting WebSocket server: {Message}\",\n                    ex.Message);\n                throw;\n            }\n        }\n\n        /// <summary>\n        /// Stops the WebSocket server and disconnects all clients.\n        /// </summary>\n        public async Task StopAsync(CancellationToken cancellationToken = default)\n        {\n            if (!_isRunning)\n                return;\n\n            _isRunning = false;\n            _serverCancellation.Cancel();\n\n            try\n            {\n                // Close all client connections\n                var disconnectTasks = _connectedClients.Values\n                    .Select(client => client.CloseAsync(\"Server shutting down\", cancellationToken))\n                    .ToArray();\n\n                await Task.WhenAll(disconnectTasks);\n\n                // Stop listening\n                _httpListener.Stop();\n\n                _logger.LogInformation(\n                    \"WebSocket server stopped. Disconnected {ClientCount} clients\",\n                    _connectedClients.Count);\n            }\n            catch (Exception ex)\n            {\n                _logger.LogError(\n                    ex,\n                    \"Error stopping WebSocket server: {Message}\",\n                    ex.Message);\n            }\n        }\n\n        /// <summary>\n        /// Broadcasts telemetry to all connected clients.\n        /// Non-blocking async sends with per-client error handling.\n        /// </summary>\n        public async Task BroadcastTelemetryAsync(\n            TelemetrySnapshot telemetry,\n            CancellationToken cancellationToken = default)\n        {\n            if (!_isRunning || telemetry == null)\n                return;\n\n            var tasks = new List<Task>();\n            var disconnectedClients = new List<string>();\n\n            try\n            {\n                foreach (var kvp in _connectedClients)\n                {\n                    var connectionId = kvp.Key;\n                    var client = kvp.Value;\n\n                    if (!client.IsConnected)\n                    {\n                        disconnectedClients.Add(connectionId);\n                        continue;\n                    }\n\n                    // Send without awaiting to achieve non-blocking broadcast\n                    tasks.Add(client.SendTelemetryAsync(telemetry, cancellationToken)\n                        .ContinueWith(async task =>\n                        {\n                            if (task.IsFaulted)\n                            {\n                                _logger.LogWarning(\n                                    \"Failed to send telemetry to client {ConnectionId}\",\n                                    connectionId);\n                                if (!client.IsConnected)\n                                {\n                                    disconnectedClients.Add(connectionId);\n                                }\n                            }\n                        }));\n                }\n\n                // Wait for all sends to complete (or timeout)\n                if (tasks.Count > 0)\n                {\n                    var timeoutCts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));\n                    try\n                    {\n                        await Task.WhenAll(tasks);\n                    }\n                    catch (OperationCanceledException)\n                    {\n                        _logger.LogDebug(\"Broadcast timeout after 100ms\");\n                    }\n                }\n\n                Interlocked.Increment(ref _totalMessages);\n            }\n            finally\n            {\n                // Remove disconnected clients\n                foreach (var connectionId in disconnectedClients)\n                {\n                    if (_connectedClients.TryRemove(connectionId, out var client))\n                    {\n                        _logger.LogInformation(\n                            \"Removed disconnected client {ConnectionId}\",\n                            connectionId);\n                    }\n                }\n            }\n        }\n\n        /// <summary>\n        /// Gets current server statistics for monitoring.\n        /// </summary>\n        public ServerStatistics GetServerStatistics()\n        {\n            return new ServerStatistics\n            {\n                ConnectedClients = _connectedClients.Count,\n                TotalConnections = Interlocked.Read(ref _totalConnections),\n                TotalMessages = Interlocked.Read(ref _totalMessages),\n                UpcomingConnectionAttempts = 0,\n                UptimeDuration = DateTime.UtcNow - _serverStartTime,\n                IsRunning = _isRunning\n            };\n        }\n\n        /// <summary>\n        /// Gets statistics for all connected clients.\n        /// </summary>\n        public List<ConnectionStatistics> GetConnectionStatistics()\n        {\n            return _connectedClients.Values\n                .Select(client => client.GetStatistics())\n                .ToList();\n        }\n\n        /// <summary>\n        /// Background loop accepting client connections.\n        /// </summary>\n        private async Task AcceptClientConnectionsAsync(CancellationToken cancellationToken)\n        {\n            try\n            {\n                while (!cancellationToken.IsCancellationRequested && _isRunning)\n                {\n                    try\n                    {\n                        // Get next HTTP context\n                        HttpListenerContext context = await _httpListener.GetContextAsync()\n                            .ConfigureAwait(false);\n\n                        // Handle WebSocket upgrade in background\n#pragma warning disable CS4014\n                        _ = HandleClientConnectionAsync(context, cancellationToken);\n#pragma warning restore CS4014\n                    }\n                    catch (HttpListenerException)\n                    {\n                        // Expected when listener is stopped\n                        break;\n                    }\n                    catch (OperationCanceledException)\n                    {\n                        // Cancellation requested\n                        break;\n                    }\n                    catch (Exception ex)\n                    {\n                        _logger.LogError(\n                            ex,\n                            \"Error accepting client connection: {Message}\",\n                            ex.Message);\n                    }\n                }\n            }\n            finally\n            {\n                _logger.LogInformation(\"Client accept loop ended\");\n            }\n        }\n\n        /// <summary>\n        /// Handles an individual client WebSocket upgrade and connection.\n        /// </summary>\n        private async Task HandleClientConnectionAsync(\n            HttpListenerContext context,\n            CancellationToken cancellationToken)\n        {\n            try\n            {\n                // Upgrade to WebSocket\n                if (!context.Request.IsWebSocketRequest)\n                {\n                    context.Response.StatusCode = 400;\n                    context.Response.Close();\n                    return;\n                }\n\n                HttpListenerWebSocketContext wsContext = await context.AcceptWebSocketAsync(null)\n                    .ConfigureAwait(false);\n                System.Net.WebSockets.WebSocket webSocket = wsContext.WebSocket;\n\n                // Create connection handler\n                var handler = new WebSocketConnectionHandler(webSocket, new LoggerFactory().CreateLogger<WebSocketConnectionHandler>());\n                var connectionId = handler.ConnectionId;\n\n                if (_connectedClients.TryAdd(connectionId, handler))\n                {\n                    Interlocked.Increment(ref _totalConnections);\n\n                    _logger.LogInformation(\n                        \"Client connected. ConnectionId: {ConnectionId}, TotalClients: {TotalClients}\",\n                        connectionId, _connectedClients.Count);\n\n                    // Start receive loop for this client in background\n#pragma warning disable CS4014\n                    _ = RunClientReceiveLoopAsync(connectionId, handler, cancellationToken);\n#pragma warning restore CS4014\n                }\n                else\n                {\n                    await webSocket.CloseAsync(\n                        WebSocketCloseStatus.InternalServerError,\n                        \"Failed to register client\",\n                        CancellationToken.None);\n                    webSocket.Dispose();\n                }\n            }\n            catch (Exception ex)\n            {\n                _logger.LogError(\n                    ex,\n                    \"Error handling client connection: {Message}\",\n                    ex.Message);\n            }\n        }\n\n        /// <summary>\n        /// Runs receive loop for a client connection.\n        /// </summary>\n        private async Task RunClientReceiveLoopAsync(\n            string connectionId,\n            WebSocketConnectionHandler handler,\n            CancellationToken cancellationToken)\n        {\n            try\n            {\n                await handler.StartReceiveLoopAsync(cancellationToken).ConfigureAwait(false);\n            }\n            finally\n            {\n                // Remove client when disconnected\n                if (_connectedClients.TryRemove(connectionId, out var removedHandler))\n                {\n                    await removedHandler.DisposeAsync().ConfigureAwait(false);\n                    _logger.LogInformation(\n                        \"Client disconnected. ConnectionId: {ConnectionId}, RemainingClients: {RemainingClients}\",\n                        connectionId, _connectedClients.Count);\n                }\n            }\n        }\n\n        private void ThrowIfDisposed()\n        {\n            if (_disposed)\n                throw new ObjectDisposedException(nameof(WebSocketServer));\n        }\n\n        public void Dispose()\n        {\n            if (_disposed)\n                return;\n\n            _disposed = true;\n\n            try\n            {\n                StopAsync(CancellationToken.None).GetAwaiter().GetResult();\n            }\n            catch (Exception ex)\n            {\n                _logger.LogError(ex, \"Error during disposal\");\n            }\n\n            _httpListener?.Close();\n            _serverCancellation?.Dispose();\n        }\n    }\n\n    /// <summary>Server statistics for monitoring and diagnostics.</summary>\n    public class ServerStatistics\n    {\n        public int ConnectedClients { get; set; }\n        public long TotalConnections { get; set; }\n        public long TotalMessages { get; set; }\n        public int UpcomingConnectionAttempts { get; set; }\n        public TimeSpan UptimeDuration { get; set; }\n        public bool IsRunning { get; set; }\n    }\n\n    /// <summary>WebSocket server interface definition.</summary>\n    public interface IWebSocketServer\n    {\n        int Port { get; }\n        bool IsRunning { get; }\n        int ConnectedClientsCount { get; }\n\n        Task StartAsync(CancellationToken cancellationToken = default);\n        Task StopAsync(CancellationToken cancellationToken = default);\n        Task BroadcastTelemetryAsync(TelemetrySnapshot telemetry, CancellationToken cancellationToken = default);\n        ServerStatistics GetServerStatistics();\n        List<ConnectionStatistics> GetConnectionStatistics();\n    }\n}\n